override_patterns:
override_patterns: [
  {
    body_type: triangle,
    override_type: acceptance_and_fired_intent,
    conditions: [
      "fired_intents includes intent_6 OR intent_9",
      "closeness_to_body_top_accepted includes relaxed OR oversized"
    ]
  }
]

intent_execution_notes:
intent_execution_notes: {

intent_2: "Tucked or front-/half-tucked into a high-rise bottom. The relaxed linen body blouses softly over the tuck, so the waist reads as a soft, self-created line at the meeting point rather than a traced one — she sets the placement and how much blouse. styling_anchor strategy: the shirt affords the waist, it doesn't impose it. Left untucked the same shirt reads Intent 6 (steps back) — the waist exists only when she makes it. Independent-definer match (Q5a = tuck, no-build) in the refined-casual register."

  intent_6: "Worn untucked, fully buttoned or partially unbuttoned, over relaxed bottoms (relaxed straight jeans, wide-leg trousers, linen shorts). Boxy hip-length silhouette + linen drape produces non-engaging coverage. Refined-casual register without body emphasis.",

  intent_9: "Worn with 2-3 buttons unbuttoned to reveal V. Décolleté becomes the visual focal point against the soft drape of the rest. The boxy body and hip-length keep the lower body covered; eye lands at the V. Best with relaxed bottoms so no proportion play competes with the opening."
}

